-- CareerSignal Africa seed data
-- Run schema.sql first, then run this file in Supabase SQL Editor.
-- Generated from src/data.js. Safe to re-run: source/career/market rows upsert; learning links are refreshed.

begin;

-- 1) Sources
on conflict (id) do update set
  name = excluded.name,
  url = excluded.url,
  type = excluded.type,
  region = excluded.region,
  updated_at = now();

-- 2) Careers
on conflict (id) do update set
  title = excluded.title,
  category = excluded.category,
  description = excluded.description,
  education_requirements = excluded.education_requirements,
  skills = excluded.skills,
  interests = excluded.interests,
  work_preferences = excluded.work_preferences,
  entry_paths = excluded.entry_paths,
  resources = excluded.resources,
  related_careers = excluded.related_careers,
  active = excluded.active,
  updated_at = now();

-- 3) Market data
on conflict (career_id, region) do update set
  marketability_score = excluded.marketability_score,
  profitability_score = excluded.profitability_score,
  demand_score = excluded.demand_score,
  median_salary_local = excluded.median_salary_local,
  median_salary_usd = excluded.median_salary_usd,
  currency_code = excluded.currency_code,
  trend = excluded.trend,
  source_ids = excluded.source_ids,
  last_updated = excluded.last_updated,
  updated_at = now();

-- 4) Learning links: refresh seeded video/blog links
delete from public.learning_links where career_id in ('software_developer', 'data_analyst', 'cybersecurity_analyst', 'ai_ml_specialist', 'renewable_energy_technician', 'mining_engineer', 'agronomist', 'nurse', 'clinical_officer', 'teacher_stem', 'accountant', 'financial_analyst', 'project_manager', 'supply_chain_manager', 'civil_engineer', 'electrical_engineer', 'environmental_scientist', 'public_health_specialist', 'monitoring_evaluation', 'digital_marketer', 'ux_designer', 'heavy_mechanic', 'hospitality_manager', 'entrepreneur_sme', 'water_sanitation_engineer', 'cloud_solutions_architect', 'product_manager', 'gis_specialist', 'actuary', 'veterinary_technician', 'automation_technician', 'telecom_network_engineer', 'construction_manager', 'social_worker', 'multimedia_producer');

-- 5) Optional sanity checks
do $$
declare
  career_count integer;
  source_count integer;
  market_count integer;
begin
  select count(*) into career_count from public.careers;
  select count(*) into source_count from public.sources;
  select count(*) into market_count from public.market_data;
  raise notice 'Seed complete. Careers: %, Sources: %, Market rows: %', career_count, source_count, market_count;
end $$;

commit;

